```bash
#!/usr/bin/env bash
set -euo pipefail

threshold="${1:-85}"

df -P -x tmpfs -x devtmpfs | awk -v t="$threshold" '
NR > 1 {
  used=$5
  gsub("%", "", used)
  if (used >= t) {
    printf "%s %s%% %s\n", $1, used, $6
  }
}
```
This script reports persistent filesystems whose usage is greater than or equal to the selected threshold.

