```bash
#!/usr/bin/env bash
set -euo pipefail

out="${1:-listening-sockets.csv}"
{
  echo "netid,state,local,process"
  sudo ss -tulpenH | awk '{
    proc=$0
    sub(/^([^ ]+[ ]+){4}/, "", proc)
    print $1 "," $2 "," $5 "," proc
  }'
} > "$out"

echo "$out"
```
This creates a simple CSV-style snapshot of listening sockets for later comparison.

