#!/usr/bin/env bash
set -euo pipefail

sudo journalctl -u ssh --since "${1:-24 hours ago}" --no-pager |
  awk '/Failed password/ {
    for (i=1; i<=NF; i++) if ($i=="for") print $(i+1)
  }' |
  sort | uniq -c | sort -nr | head -n 20
```
This summarizes usernames seen in recent failed SSH password attempts.
